function loadJson(key, fallback){ try{ const raw = localStorage.getItem(key); return raw ? JSON.parse(raw) : fallback; }catch{ return fallback; } }
function createFreshState(){ const fresh = structuredClone(DEFAULT_UI); const uiPrefs = loadJson(STORAGE.ui, {}); fresh.displayScale = uiPrefs.displayScale || DEFAULT_UI.displayScale; fresh.compareBaseId = uiPrefs.compareBaseId || ''; fresh.compareMode = uiPrefs.compareMode || compareModeDefault; return fresh; }
function persistState(){ localStorage.setItem(STORAGE.ui, JSON.stringify({displayScale:state.displayScale||DEFAULT_UI.displayScale, compareBaseId:state.compareBaseId||'', compareMode:state.compareMode||compareModeDefault})); localStorage.setItem(STORAGE.history, JSON.stringify(historyItems)); localStorage.setItem(STORAGE.saved, JSON.stringify(savedItems)); localStorage.setItem(STORAGE.compare, JSON.stringify(compareIds)); localStorage.setItem(STORAGE.sort, $('savedSort')?.value || savedSortDefault); }
function formatNumber(v,digits=2){ if(v===''||v===null||v===undefined||Number.isNaN(Number(v))) return '-'; return new Intl.NumberFormat('ja-JP',{maximumFractionDigits:digits,minimumFractionDigits:0}).format(Number(v)); }
function num(v){ const n=Number(v); return Number.isFinite(n)?n:0; }
function escapeHtml(v){ return String(v ?? '').replace(/[&<>"']/g, s=>({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}[s])); }
function showToast(msg){ const t=$('toast'); if(!t) return; t.textContent=msg; t.classList.add('show'); setTimeout(()=>t.classList.remove('show'),1800); }
function uid(){ return crypto.randomUUID ? crypto.randomUUID() : 'id_'+Date.now()+'_'+Math.random().toString(16).slice(2); }
function setSelectOptions(el, options, placeholder='選択してください', selected=''){ if(!el) return; const current=String(selected ?? ''); el.innerHTML = `<option value="">${escapeHtml(placeholder)}</option>` + options.map(o=>{ const opt=typeof o==='object'?o:{value:String(o),label:String(o)}; return `<option value="${escapeHtml(opt.value)}">${escapeHtml(opt.label)}</option>`; }).join(''); el.value = [...el.options].some(o=>o.value===current) ? current : ''; }
function cableSizes(type=state.cableType){ return Object.keys(CABLE_DATA[type] || {}).map(Number).sort((a,b)=>a-b); }
function cableInfo(type, size){ return CABLE_DATA[type]?.[Number(size)] || null; }
function isThreePhase(){ return String(state.powerSystem || '').startsWith('3φ'); }
function calcTypeLabel(){ return state.calculationType === 'lighting' ? '低圧電灯幹線計算' : '低圧動力幹線計算'; }
function calcModeLabel(v=state.calcMode){ return v === 'existing' ? '既設開閉器指定' : '自動選定'; }
function normalizePowerSystemForCalcType(){ const opts = state.calculationType === 'power' ? ['3φ3W','3φ4W'] : ['1φ2W','1φ3W']; if(!opts.includes(state.powerSystem)) state.powerSystem = opts[0]; if(state.calculationType === 'lighting' && state.cableType === 'CVT') state.cableType='CV-2C'; if(state.calculationType === 'power' && !state.cableType) state.cableType='CVT'; }
function nextBreaker(current){ return BREAKER_SIZES.find(v => v >= current) || BREAKER_SIZES.at(-1); }
function requiredBreakerFromLoad(){ return nextBreaker(getLoadSummary().totalCurrent); }
function recommendedBreaker(){ if(state.calcMode === 'existing' && state.existingBreaker) return num(state.existingBreaker); const margin = Math.max(0.1, num(state.breakerMarginRatio || 0.8)); return nextBreaker(getLoadSummary().totalCurrent / margin); }
function getCorrectionBreakdown(){ const t=TEMP_COEF[num(state.ambientTemperature)] ?? 1; const p=PARALLEL_COEF[num(state.parallelCount)] ?? 1; const m=METHOD_COEF[state.installationMethod] ?? 1; const c=CONDITION_COEF[state.layingCondition] ?? 1; return {temperature:t,parallel:p,method:m,condition:c,final:t*p*m*c}; }
function correctedAmpacityFor(info){ return info ? Number(info.ampacity || 0) * getCorrectionBreakdown().final : 0; }
function dropCalc(current, resistance, length){ const l=num(length); const r=num(resistance); const v=num(state.voltage); if(!current||!r||!l||!v) return {dropV:0,dropPercent:0}; const dropV = isThreePhase() ? Math.sqrt(3)*current*r*l/1000 : 2*current*r*l/1000; return {dropV, dropPercent:(dropV/v)*100}; }
function rackWidthFor(outer, count){ const need = outer * Math.max(1,count) * 1.6 + 80; return RACK_WIDTHS.find(w=>w>=need) || `${RACK_WIDTHS.at(-1)}以上`; }
function getLoadSummary(){ const list = state.loads.map((load,index)=>{ const value=num(load.value); const pf=num(state.powerFactor || 1); const eff=num(state.efficiency || 1); const voltage=num(state.voltage); let current=0, kw=0, kva=0; if(load.inputType === 'A'){ current=value; kva=isThreePhase()?Math.sqrt(3)*voltage*current/1000:voltage*current/1000; kw=kva*pf*eff; } else if(load.inputType === 'kVA'){ kva=value; kw=kva*pf*eff; current=isThreePhase()?kva*1000/(Math.sqrt(3)*voltage):kva*1000/voltage; } else { kw=value; kva=(pf*eff) ? kw/(pf*eff) : 0; current=isThreePhase()?kw*1000/(Math.sqrt(3)*voltage*pf*eff):kw*1000/(voltage*pf*eff); } return {no:index+1,name:load.name||'',inputType:load.inputType||'',value:value,current,kw,kva}; }); return {list,totalCurrent:list.reduce((a,b)=>a+b.current,0),totalKW:list.reduce((a,b)=>a+b.kw,0),totalKVA:list.reduce((a,b)=>a+b.kva,0)}; }
function cableCandidateBySize(breaker, size){ const info = cableInfo(state.cableType, size); if(!info) return null; const corrected = correctedAmpacityFor(info); const summary = getLoadSummary(); const drop = dropCalc(summary.totalCurrent, info.resistance, state.wiringLength); return {type:state.cableType,size:Number(size),info,basis:info.ampacity,corrected,drop,ok:corrected>=breaker && drop.dropPercent<=DROP_LIMIT_PERCENT}; }
function cableSelectionForBreaker(breaker){ const candidates = cableSizes().map(size=>cableCandidateBySize(breaker,size)).filter(Boolean); return {candidates, valid:candidates.find(c=>c.ok) || null}; }
function candidateLabel(c){ return c ? `${c.type} ${c.size}sq` : '-'; }
function allSelectionReasons(c){ if(!c) return ['条件に合うケーブル候補がありません。']; const out=[]; out.push(`判定対象：${candidateLabel(c)}`); out.push(`補正後許容電流 ${formatNumber(c.corrected,1)}A / 推奨開閉器 ${formatNumber(recommendedBreaker(),1)}A`); out.push(`電圧降下 ${formatNumber(c.drop.dropPercent,2)}% / 目安 ${DROP_LIMIT_PERCENT.toFixed(1)}%以下`); return out; }
function primaryFactor(c){ if(!c) return '候補なし'; if(c.corrected < recommendedBreaker()) return '許容電流'; if(c.drop.dropPercent > DROP_LIMIT_PERCENT) return '電圧降下'; return '許容電流・電圧降下'; }
function capacityMarginKW(breaker, summary){ const v=num(state.voltage), pf=num(state.powerFactor), eff=num(state.efficiency); const capacity = isThreePhase() ? Math.sqrt(3)*v*breaker*pf*eff/1000 : v*breaker*pf*eff/1000; return capacity - summary.totalKW; }
function constructionNotes(totalMass){ const notes=['本結果は参考値です。現場条件、施工方法、仕様書、保護協調を確認してください。']; if(totalMass>100) notes.push('概算総質量が大きいため、支持・ラック・吊り金物・搬入方法を確認してください。'); return notes; }
function rootMemo(){ return ['ケーブル許容電流・外径・質量は参考値です。最終値は仕様書および内線規定等で確認してください。','推奨開閉器は合計電流÷開閉器裕度設定を基準に直近上位で選定します。']; }

function normalizeLoads(){ const count=num(state.loadCount); while(state.loads.length<count) state.loads.push({id:uid(),name:'',inputType:'kW',value:''}); state.loads = state.loads.slice(0,count); }
function refreshLoadPosition(){ const label=$('loadPositionLabel'); if(!label) return; const count=state.loads.length; if(!count){ label.textContent='- / -'; return; } label.textContent=`1 / ${count}`; }
function renderLoadCards(){ normalizeLoads(); const box=$('loadCards'); if(!box) return; if(!state.loads.length){ box.innerHTML='<div class="muted">負荷数を選択すると入力欄が表示されます。</div>'; refreshLoadPosition(); return; } box.innerHTML = state.loads.map((load,index)=>`<article class="load-card"><div class="panel-title">負荷 ${index+1}</div><div class="grid"><label><span>負荷名称</span><input id="load-name-${load.id}" data-load-id="${load.id}" data-load-field="name" type="text" value="${escapeHtml(load.name)}" /></label><label><span>入力方式</span><select id="load-type-${load.id}" data-load-id="${load.id}" data-load-field="inputType"><option value="kW" ${load.inputType==='kW'?'selected':''}>kW</option><option value="kVA" ${load.inputType==='kVA'?'selected':''}>kVA</option><option value="A" ${load.inputType==='A'?'selected':''}>A</option></select></label><label><span>負荷値</span><input id="load-value-${load.id}" data-load-id="${load.id}" data-load-field="value" type="number" inputmode="decimal" value="${escapeHtml(load.value)}" /></label></div></article>`).join(''); box.querySelectorAll('[data-load-field]').forEach(el=>el.addEventListener('input',onLoadEdit)); box.querySelectorAll('select[data-load-field]').forEach(el=>el.addEventListener('change',onLoadEdit)); box.onscroll = () => { const cards=[...box.querySelectorAll('.load-card')]; const idx=Math.max(0, cards.findIndex(card=>card.getBoundingClientRect().left >= box.getBoundingClientRect().left - 20)); $('loadPositionLabel').textContent=`${idx+1} / ${cards.length}`; }; refreshLoadPosition(); }
function onLoadEdit(e){ const id=e.currentTarget.dataset.loadId, field=e.currentTarget.dataset.loadField; const load=state.loads.find(l=>l.id===id); if(load){ load[field]=e.currentTarget.value; persistState(); validateRealtime(); } }

function renderForm(){ normalizePowerSystemForCalcType(); setSelectOptions($('calcMode'),[{value:'auto',label:'自動選定'},{value:'existing',label:'既設開閉器指定'}],'選択してください',state.calcMode); const systems=state.calculationType==='power'?['3φ3W','3φ4W']:['1φ2W','1φ3W']; setSelectOptions($('powerSystem'),systems,'選択してください',state.powerSystem); const voltages=state.calculationType==='power'?[200,210,400,440]:[100,200]; setSelectOptions($('voltage'),voltages.map(v=>({value:String(v),label:`${v}V`})),'選択してください',state.voltage); setSelectOptions($('powerFactor'),POWER_FACTOR_OPTIONS,'選択してください',state.powerFactor); setSelectOptions($('efficiency'),EFFICIENCY_OPTIONS,'選択してください',state.efficiency); setSelectOptions($('existingBreaker'),BREAKER_SIZES.map(v=>({value:String(v),label:`${v}A`})),'選択してください',state.existingBreaker); setSelectOptions($('breakerMarginRatio'),BREAKER_MARGIN_RATIO_OPTIONS,'選択してください',state.breakerMarginRatio||'0.8'); setSelectOptions($('loadCount'),Array.from({length:20},(_,i)=>({value:String(i+1),label:String(i+1)})),'選択してください',state.loadCount); setSelectOptions($('cableSizingMode'),CABLE_SIZING_MODE_OPTIONS,'選択してください',state.cableSizingMode||'auto'); setSelectOptions($('cableType'),Object.keys(CABLE_DATA),'選択してください',state.cableType); setSelectOptions($('cableSize'),cableSizes().map(v=>({value:String(v),label:`${v}sq`})),'選択してください',state.cableSize); setSelectOptions($('installationMethod'),Object.keys(METHOD_COEF),'選択してください',state.installationMethod); setSelectOptions($('layingCondition'),Object.keys(CONDITION_COEF),'選択してください',state.layingCondition); setSelectOptions($('ambientTemperature'),Object.keys(TEMP_COEF).map(v=>({value:String(v),label:`${v}℃`})),'選択してください',state.ambientTemperature); setSelectOptions($('parallelCount'),Object.keys(PARALLEL_COEF),'選択してください',state.parallelCount); setSelectOptions($('displayScale'),DISPLAY_SCALE_OPTIONS,'選択してください',state.displayScale||'1.0'); setSelectOptions($('savedSort'),SORT_OPTIONS,'選択してください',localStorage.getItem(STORAGE.sort)||savedSortDefault); ['wiringLength','projectName','constructionType','submittedTo','drawingNo','createdBy','projectRemarks','baseAmpacity'].forEach(id=>{ if($(id)) $(id).value=state[id]||''; }); $('calcModeHint').textContent = state.calcMode==='existing' ? '既設開閉器サイズを基準に幹線サイズを判定します。' : '推奨開閉器は、合計電流÷開閉器裕度設定で選定します。'; document.querySelectorAll('.seg').forEach(btn=>btn.classList.toggle('active',btn.dataset.calcType===state.calculationType)); $('versionText').textContent = VERSIONS.app; applyDisplayScale(); renderLoadCards(); renderAmpacitySection(); }
function renderAmpacitySection(){ const info=cableInfo(state.cableType,state.cableSize); if(info && state.ampacityMode!=='manual'){ state.baseAmpacity=String(info.ampacity||''); state.ampacityMode='auto'; } const breakdown=getCorrectionBreakdown(); const corrected=num(state.baseAmpacity)*breakdown.final; const mass=info?num(info.massKgKm)/1000:0; const totalMass=mass*num(state.wiringLength)*num(state.parallelCount||1); $('baseAmpacity').value = state.baseAmpacity || ''; $('correctedAmpacityValue').textContent = formatNumber(corrected,1); $('coefTemperature').textContent = formatNumber(breakdown.temperature,2); $('coefParallel').textContent = formatNumber(breakdown.parallel,2); $('coefMethod').textContent = formatNumber(breakdown.method,2); $('coefCondition').textContent = formatNumber(breakdown.condition,2); $('coefFinal').textContent = formatNumber(breakdown.final,2); $('massPerMeter').textContent = mass ? formatNumber(mass,3) : '-'; $('massTotal').textContent = totalMass ? formatNumber(totalMass,1) : '-'; $('rackWidthValue').textContent = info ? rackWidthFor(num(info.outerDiameter), num(state.parallelCount||1)) : '-'; const badge=$('ampacityModeBadge'); badge.textContent = state.ampacityMode==='manual' ? '手動' : (state.baseAmpacity ? '自動' : '未設定'); badge.className = 'mode-badge ' + (state.ampacityMode==='manual' ? 'manual' : (state.baseAmpacity ? '' : 'none')); }
function applyDisplayScale(){ document.documentElement.style.setProperty('--display-scale', state.displayScale || '1'); }
function renderAll(){ renderForm(); renderDocs(); renderSaved(); if(state.lastResult){ $('resultPanel').classList.remove('hidden'); $('resultBody').classList.remove('hidden'); renderResult(); } else { $('resultPanel').classList.add('hidden'); } }

function missingFields(){ const missing=[]; const push=(condition,label,id)=>{ if(condition) missing.push({label,id}); }; push(!state.calcMode,'計算方式を選択してください。','calcMode'); push(!state.powerSystem,'電源方式を選択してください。','powerSystem'); push(!state.voltage,'電圧を選択してください。','voltage'); push(!state.powerFactor,'力率を選択してください。','powerFactor'); push(!state.efficiency,'効率を選択してください。','efficiency'); push(!state.wiringLength,'配線長を入力してください。','wiringLength'); if(state.calcMode==='existing') push(!state.existingBreaker,'既設開閉器を選択してください。','existingBreaker'); if(state.calcMode!=='existing') push(!state.breakerMarginRatio,'開閉器裕度設定を選択してください。','breakerMarginRatio'); push(!state.loadCount,'負荷数を選択してください。','loadCount'); push(!state.cableType,'ケーブル種類を選択してください。','cableType'); push(!state.cableSizingMode,'ケーブルサイズ選定を選択してください。','cableSizingMode'); if(state.cableSizingMode==='manual'){ push(!state.cableSize,'任意ケーブルサイズを選択してください。','cableSize'); push(!state.baseAmpacity,'ケーブル許容電流を入力してください。','baseAmpacity'); } push(!state.installationMethod,'敷設方法を選択してください。','installationMethod'); push(!state.layingCondition,'敷設条件を選択してください。','layingCondition'); push(!state.ambientTemperature,'環境温度を選択してください。','ambientTemperature'); push(!state.parallelCount,'条数を選択してください。','parallelCount'); state.loads.forEach((load,index)=>{ if(!load.name) missing.push({label:`負荷${index+1}の負荷名称を入力してください。`,id:`load-name-${load.id}`}); if(!load.inputType) missing.push({label:`負荷${index+1}の入力方式を選択してください。`,id:`load-type-${load.id}`}); if(load.value===''||load.value===null||load.value===undefined) missing.push({label:`負荷${index+1}の負荷値を入力してください。`,id:`load-value-${load.id}`}); }); return missing; }
function clearInputErrors(){ document.querySelectorAll('.input-error').forEach(el=>el.classList.remove('input-error')); }
function markMissingFields(list){ clearInputErrors(); list.forEach(item=>$(item.id)?.classList.add('input-error')); }
function updateResultError(message){ const box=$('resultErrorBox'); if(!message){ box.classList.add('hidden'); box.innerHTML=''; return; } box.classList.remove('hidden'); box.innerHTML=message; }
function validateRealtime(){ renderAmpacitySection(); }
function calculate(){ const missing=missingFields(); if(missing.length){ markMissingFields(missing); state.lastResult=null; $('resultPanel').classList.remove('hidden'); updateResultError(`未入力項目がある為、計算出来ません。入力して下さい。<br>${missing.map(v=>'・'+escapeHtml(v.label)).join('<br>')}`); $('resultBody').classList.add('hidden'); persistState(); return; } clearInputErrors(); const summary=getLoadSummary(); const requiredBreaker=requiredBreakerFromLoad(); const recommended=recommendedBreaker(); const requiredSelection=cableSelectionForBreaker(requiredBreaker); const recommendedSelection=cableSelectionForBreaker(recommended); const requiredCandidate=requiredSelection.valid || requiredSelection.candidates.at(-1) || null; const recommendedCandidate=recommendedSelection.valid || recommendedSelection.candidates.at(-1) || null; const manualCandidate=state.cableSize ? cableCandidateBySize(recommended,num(state.cableSize)) : null; const candidate=(state.cableSizingMode||'auto')==='manual' ? manualCandidate : recommendedCandidate; const breakdown=getCorrectionBreakdown(); const fail=[]; const currentOk=!!candidate && candidate.corrected>=recommended; const dropOk=!!candidate && candidate.drop.dropPercent<=DROP_LIMIT_PERCENT; const breakerOk=recommended>=requiredBreaker; if(!currentOk) fail.push(`指定ケーブル許容電流不足（推奨開閉器 ${formatNumber(recommended,1)}A / 補正後許容 ${formatNumber(candidate?.corrected,1)}A）`); if(!breakerOk) fail.push(`開閉器容量不足（必要 ${requiredBreaker}A / 推奨 ${recommended}A）`); if(!dropOk) fail.push(`電圧降下超過（${formatNumber(candidate?.drop.dropPercent,2)}% / 許容 ${DROP_LIMIT_PERCENT.toFixed(1)}%）`); const info=candidate?.info; const massKgM=info ? num(info.massKgKm)/1000 : 0; const totalMass=massKgM*num(state.wiringLength)*num(state.parallelCount||1); const breakerMarginPercent=recommended ? ((recommended-summary.totalCurrent)/recommended)*100 : 0; const result={calculatedAt:new Date().toISOString(),mode:state.calcMode,calculationType:state.calculationType,projectName:state.projectName||'',constructionType:state.constructionType||'',submittedTo:state.submittedTo||'',drawingNo:state.drawingNo||'',createdBy:state.createdBy||'',projectRemarks:state.projectRemarks||'',powerSystem:state.powerSystem,voltage:state.voltage,powerFactor:state.powerFactor,efficiency:state.efficiency,wiringLength:state.wiringLength,totalCurrent:summary.totalCurrent,totalKW:summary.totalKW,totalKVA:summary.totalKVA,requiredBreaker,adoptedBreaker:recommended,breakerMarginRatio:state.breakerMarginRatio||'0.8',breakerMarginPercent,capacityMarginKW:capacityMarginKW(recommended,summary),voltageDropV:candidate?.drop.dropV||0,voltageDropPercent:candidate?.drop.dropPercent||0,baseAmpacity:candidate?.basis||num(state.baseAmpacity),correctedAmpacity:candidate?.corrected||0,cableType:state.cableType,cableSize:candidate?.size||state.cableSize,cableSizingMode:state.cableSizingMode,requiredMinCableType:state.cableType,requiredMinCableSize:requiredCandidate?.size||'',requiredMinCableCorrectedAmpacity:requiredCandidate?.corrected||0,requiredMinCableVoltageDropPercent:requiredCandidate?.drop.dropPercent||0,recommendedCableType:state.cableType,recommendedCableSize:recommendedCandidate?.size||'',recommendedCableCorrectedAmpacity:recommendedCandidate?.corrected||0,recommendedCableVoltageDropPercent:recommendedCandidate?.drop.dropPercent||0,correctionBreakdown:breakdown,reasons:allSelectionReasons(candidate),mainFactor:primaryFactor(candidate),failReasons:fail,judgement:fail.length?'否':'良',existingBreaker:state.existingBreaker||'',existingBreakerJudge:state.calcMode==='existing'?(breakerOk?'適合':'否'):'-',cableJudge:currentOk&&dropOk?'適合':'否',rackWidth:info?rackWidthFor(num(info.outerDiameter),num(state.parallelCount||1)):'-',massKgM,massTotalKg:totalMass,constructionNotes:constructionNotes(totalMass),rootMemo:rootMemo(),loadDetails:summary.list}; state.lastResult=result; historyItems.unshift({id:uid(),title:`${calcTypeLabel()}_${new Date().toLocaleString('sv-SE').replace(/[: ]/g,'_')}`,memo:'',savedAt:new Date().toISOString(),input:structuredClone(state),result:structuredClone(result),calculationMode:state.calcMode,versions:structuredClone(VERSIONS)}); historyItems=historyItems.slice(0,50); persistState(); $('resultPanel').classList.remove('hidden'); $('resultBody').classList.remove('hidden'); updateResultError(''); renderResult(); renderSaved(); setTimeout(()=>$('resultPanel').scrollIntoView({behavior:'smooth',block:'start'}),0); }

function renderResult(){ const r=state.lastResult; if(!r) return; const set=(id,v)=>{ if($(id)) $(id).textContent=v; }; set('resLoadCount',r.loadDetails.length); set('resTotalKW',formatNumber(r.totalKW,3)); set('resTotalKVA',formatNumber(r.totalKVA,3)); set('resTotalCurrent',formatNumber(r.totalCurrent,2)); set('resRequiredBreaker',`${r.requiredBreaker}A`); set('resRecommendedBreaker',`${r.adoptedBreaker}A`); set('resRequiredCable',r.requiredMinCableSize?`${r.requiredMinCableType} ${r.requiredMinCableSize}sq`:'-'); set('resRecommendedCable',r.recommendedCableSize?`${r.recommendedCableType} ${r.recommendedCableSize}sq`:'-'); set('resManualCable',r.cableSizingMode==='manual'?`${r.cableType} ${r.cableSize}sq`:'-'); set('resSelectedCable',`${r.cableType} ${r.cableSize}sq`); set('resBaseAmpacity',formatNumber(r.baseAmpacity,1)); set('resCorrectedAmpacity',formatNumber(r.correctedAmpacity,1)); set('resDropV',formatNumber(r.voltageDropV,2)); set('resDropPct',formatNumber(r.voltageDropPercent,2)); set('resBreakerMargin',formatNumber(r.breakerMarginPercent,1)); set('resCapacityMargin',formatNumber(r.capacityMarginKW,2)); set('resMassPerM',formatNumber(r.massKgM,3)); set('resMassTotal',formatNumber(r.massTotalKg,1)); set('resRackWidth',r.rackWidth); set('resJudgement',r.judgement); $('resJudgement').className = r.judgement==='良'?'status-ok':'status-ng'; $('resultReasons').innerHTML = [`<div class="readonly-row"><span>選定主因</span><strong>${escapeHtml(r.mainFactor)}</strong></div>`,...r.reasons.map(v=>`<div class="muted">・${escapeHtml(v)}</div>`),...r.failReasons.map(v=>`<div class="fail-item">${escapeHtml(v)}</div>`),...r.rootMemo.map(v=>`<div class="muted">※ ${escapeHtml(v)}</div>`)].join(''); $('loadResultTable').innerHTML = `<thead><tr><th>No</th><th>負荷名称</th><th>入力方式</th><th>負荷値</th><th>換算電流[A]</th><th>換算容量[kW]</th><th>換算容量[kVA]</th></tr></thead><tbody>${r.loadDetails.map(l=>`<tr><td>${l.no}</td><td>${escapeHtml(l.name)}</td><td>${escapeHtml(l.inputType)}</td><td>${formatNumber(l.value,3)}</td><td>${formatNumber(l.current,2)}</td><td>${formatNumber(l.kw,3)}</td><td>${formatNumber(l.kva,3)}</td></tr>`).join('')}</tbody>`; }
function commonRows(){ const r=state.lastResult; return [['工事件名',r.projectName],['工事種別',r.constructionType||calcTypeLabel()],['提出先',r.submittedTo],['図番',r.drawingNo],['作成者',r.createdBy],['備考',r.projectRemarks],['計算方式',calcModeLabel(r.mode)],['電源方式',r.powerSystem],['電圧[V]',r.voltage],['力率',r.powerFactor],['効率',r.efficiency],['配線長[m]',r.wiringLength],['既設開閉器[A]',r.existingBreaker],['開閉器裕度設定',r.breakerMarginRatio],['必要最小開閉器[A]',r.requiredBreaker],['推奨開閉器[A]',r.adoptedBreaker],['必要最小ケーブル',r.requiredMinCableSize?`${r.requiredMinCableType} ${r.requiredMinCableSize}sq`:''],['自動推奨ケーブル',r.recommendedCableSize?`${r.recommendedCableType} ${r.recommendedCableSize}sq`:''],['任意ケーブルサイズ',r.cableSizingMode==='manual'?`${r.cableType} ${r.cableSize}sq`:'' ],['判定対象ケーブル',`${r.cableType} ${r.cableSize}sq`],['ケーブル許容電流[A]',r.baseAmpacity],['補正後許容電流[A]',r.correctedAmpacity],['合計容量[kW]',r.totalKW],['合計容量[kVA]',r.totalKVA],['合計電流[A]',r.totalCurrent],['電圧降下[V]',r.voltageDropV],['電圧降下[%]',r.voltageDropPercent],['開閉器裕度[%]',r.breakerMarginPercent],['容量裕度[kW]',r.capacityMarginKW],['概算質量[kg/m]',r.massKgM],['合計概算質量[kg]',r.massTotalKg],['参考ラック幅',r.rackWidth],['良否判定',r.judgement],['選定主因',r.mainFactor],['選定根拠',r.reasons.join('、')],['許容電流データ版',VERSIONS.ampacity],['外径・質量データ版',VERSIONS.physical],['帳票様式版',VERSIONS.form]]; }
function downloadCsv(){ if(!state.lastResult) return showToast('先に計算してください。'); const r=state.lastResult; const rows=[['項目','値'],...commonRows(),[],['負荷No','負荷名称','入力方式','負荷値','換算電流[A]','換算容量[kW]','換算容量[kVA]']]; r.loadDetails.forEach(l=>rows.push([l.no,l.name,l.inputType,l.value,l.current,l.kw,l.kva])); const csv=rows.map(row=>row.map(v=>`"${String(v??'').replaceAll('"','""')}"`).join(',')).join('\n'); downloadBlob(new Blob(['\ufeff'+csv],{type:'text/csv;charset=utf-8;'}),`${r.projectName||'feeder_calc'}_${Date.now()}.csv`); }
function excelSafe(v){ return escapeHtml(v).replace(/\n/g,'<br>'); }
function downloadExcel(){ if(!state.lastResult) return showToast('先に計算してください。'); const r=state.lastResult; const html=`<html><head><meta charset="utf-8"><style>body{font-family:"Yu Gothic",Meiryo,sans-serif}table{border-collapse:collapse;margin-bottom:18px}th,td{border:1px solid #999;padding:6px 8px;mso-number-format:"\\@"}th{background:#eaf2ff}.note{color:#c00;font-weight:bold}</style></head><body><h1>低圧幹線計算 結果表</h1><p class="note">本帳票は参考資料です。内線規定・関係法令・現場仕様・機器仕様・保護協調等を確認し、最終判断は利用者責任で行ってください。</p><h2>計算結果</h2><table>${commonRows().map(row=>`<tr><th>${excelSafe(row[0])}</th><td>${excelSafe(row[1])}</td></tr>`).join('')}</table><h2>負荷一覧</h2><table><tr><th>No</th><th>負荷名称</th><th>入力方式</th><th>負荷値</th><th>換算電流[A]</th><th>換算容量[kW]</th><th>換算容量[kVA]</th></tr>${r.loadDetails.map(l=>`<tr><td>${l.no}</td><td>${excelSafe(l.name)}</td><td>${excelSafe(l.inputType)}</td><td>${formatNumber(l.value,3)}</td><td>${formatNumber(l.current,2)}</td><td>${formatNumber(l.kw,3)}</td><td>${formatNumber(l.kva,3)}</td></tr>`).join('')}</table><h2>施工参考メモ</h2><table>${r.constructionNotes.map(n=>`<tr><td>${excelSafe(n)}</td></tr>`).join('')}</table></body></html>`; downloadBlob(new Blob(['\ufeff'+html],{type:'application/vnd.ms-excel;charset=utf-8;'}),`${r.projectName||'feeder_calc'}_${Date.now()}.xls`); }
function downloadBlob(blob,name){ const url=URL.createObjectURL(blob); const a=document.createElement('a'); a.href=url; a.download=name; a.click(); URL.revokeObjectURL(url); }
function printPdf(){ if(!state.lastResult) return showToast('先に計算してください。'); if(confirm('本帳票は参考資料です。最終判断は利用者責任で行ってください。続行しますか？')) window.print(); }

function table(headers, rows){ return `<div class="doc-table-wrap"><table class="doc-table"><thead><tr>${headers.map(h=>`<th>${escapeHtml(h)}</th>`).join('')}</tr></thead><tbody>${rows.map(row=>`<tr>${row.map(c=>`<td>${escapeHtml(c)}</td>`).join('')}</tr>`).join('')}</tbody></table></div>`; }
function buildCableDoc(){ const rows=[]; Object.entries(CABLE_DATA).forEach(([type,data])=>Object.entries(data).forEach(([size,info])=>rows.push([type,`${size}sq`,info.ampacity,info.outerDiameter,info.massKgKm,info.resistance]))); return `<p class="muted">参考値です。最終確認は仕様書・内線規定・現場条件で行ってください。</p>${table(['種類','サイズ','ケーブル許容電流[A]','外径[mm]','質量[kg/km]','導体抵抗[Ω/km]'],rows)}`; }
function buildBreakerDoc(){ return `<p class="muted">必要最小開閉器は合計電流の直近上位、推奨開閉器は合計電流÷開閉器裕度設定の直近上位で表示します。既設開閉器指定時は既設値を判定基準にします。</p>`; }
function buildResinConduitDoc(){ return Object.entries(RESIN_CONDUIT).map(([name,rows])=>`<h3>${escapeHtml(name)}</h3>${table(['サイズ','外径[mm]','近似内径[mm]','長さ','単位質量'],rows.map(r=>[r.size,r.outer,r.inner,r.length,r.mass]))}`).join(''); }
function buildMetalConduitDoc(){ return Object.entries(METAL_CONDUIT).map(([name,rows])=>`<h3>${escapeHtml(name)}</h3>${table(['サイズ','外径[mm]','近似内径[mm]','厚さ[mm]','単位質量[kg/m]','長さ[mm]'],rows.map(r=>[r.size,r.outer,r.inner,r.thick,r.mass,r.length]))}`).join(''); }
function buildFlexibleConduitDoc(){ return Object.entries(FLEXIBLE_CONDUIT).map(([name,rows])=>`<h3>${escapeHtml(name)}</h3>${table(['サイズ','外径[mm]','近似内径[mm]','単位質量'],rows.map(r=>[r.size,r.outer,r.inner,r.mass]))}`).join(''); }
function buildDataIssuesDoc(){ return table(['項目','扱い'],DATA_ISSUES); }
function buildRackWidthDoc(){ return `<p class="muted">参考ラック幅は、ケーブル外径×条数に施工余裕を見込んだ簡易目安です。実際は支持間隔、荷重、曲げ半径、施工スペースを確認してください。</p>`; }
function buildGroundBasisDoc(){ return table(['種別','概要','備考'],[['A種','高圧・特別高圧機器の金属体等','関係法令・設計条件による'],['B種','変圧器二次側接地等','接地抵抗値は条件により異なる'],['C種','300V超の低圧機器金属体等','漏電遮断器の有無等を確認'],['D種','300V以下の低圧機器金属体等','漏電遮断器の有無等を確認'],['ELB','漏電遮断器併用時の参考扱い','現場条件で確認']]); }
function buildGroundWireDoc(){ return table(['接地種別','線種','開閉器上限[A]','参考サイズ'],GROUND_RULES.map(r=>[r.groundType,r.wireType,r.maxBreaker,r.size])); }
function buildHvSymbolsDoc(){ return table(['略記号','概要'],[['PAS','柱上気中開閉器'],['DS','断路器'],['LBS','高圧交流負荷開閉器'],['VCB','真空遮断器'],['CT','変流器'],['VT','計器用変圧器']]); }
function renderDocs(){ const q=($('docsSearch')?.value||'').trim(); const box=$('docsList'); if(!box) return; box.innerHTML = DOC_GROUPS.map(group=>{ const items=group.items.filter(item=>!q || (group.title+item.title+item.build()).includes(q)); if(!items.length) return ''; return `<article class="doc-group-card"><button class="doc-group-toggle" data-doc-group="${group.key}">${escapeHtml(group.title)}</button><div class="doc-items open">${items.map(item=>`<article class="doc-item-card"><button class="doc-item-toggle" data-doc-id="${item.id}">${escapeHtml(item.title)}</button><div id="doc-content-${item.id}" class="doc-content top-gap hidden">${item.build()}</div></article>`).join('')}</div></article>`; }).join('') || '<div class="panel muted">該当する資料がありません。</div>'; box.querySelectorAll('.doc-item-toggle').forEach(btn=>btn.addEventListener('click',()=>{ const el=$(`doc-content-${btn.dataset.docId}`); el.classList.toggle('hidden'); })); }

function openSaveDialog(){ if(!state.lastResult) return showToast('先に計算してください。'); $('saveTitleInput').value = state.projectName || `${calcTypeLabel()}_${new Date().toLocaleString('sv-SE').replace(/[: ]/g,'_')}`; $('saveMemoInput').value = state.projectRemarks || ''; $('saveDialog').showModal(); }
function confirmSave(){ const title=$('saveTitleInput').value.trim(); if(!title) return showToast('保存名を入力してください。'); const idx=savedItems.findIndex(i=>i.title===title); const item={id:idx>=0?savedItems[idx].id:uid(),title,memo:$('saveMemoInput').value.trim(),savedAt:new Date().toISOString(),input:structuredClone(state),result:structuredClone(state.lastResult),calculationMode:state.calcMode,versions:structuredClone(VERSIONS)}; if(idx>=0){ savedItems[idx]=item; showToast('同名の保存データを上書きしました。'); } else { savedItems.unshift(item); savedItems=savedItems.slice(0,MAX_SAVED_ITEMS); showToast('保存しました。'); } persistState(); renderSaved(); $('saveDialog').close(); }
function sortItems(items){ const mode=$('savedSort')?.value || savedSortDefault; return [...items].sort((a,b)=>mode==='oldest'?new Date(a.savedAt)-new Date(b.savedAt):mode==='title'?String(a.title).localeCompare(String(b.title),'ja'):new Date(b.savedAt)-new Date(a.savedAt)); }
function buildSaveCard(item,isHistory=false){ const selected=compareIds.includes(item.id); const div=document.createElement('div'); div.className='saved-card'; div.innerHTML=`<div class="saved-line"><div><div class="saved-title-row"><strong>${escapeHtml(item.title||'無題')}</strong><span class="badge ${item.result?.judgement==='良'?'good':'bad'}">${escapeHtml(item.result?.judgement||'-')}</span></div><span class="muted">${new Date(item.savedAt).toLocaleString('ja-JP')}</span></div></div>${item.memo?`<div class="muted top-gap">${escapeHtml(item.memo)}</div>`:''}<div class="readonly-grid top-gap"><div><span>計算方式</span><strong>${escapeHtml(calcModeLabel(item.calculationMode))}</strong></div><div><span>判定対象ケーブル</span><strong>${escapeHtml(item.result?.cableType||'-')} ${item.result?.cableSize?item.result.cableSize+'sq':''}</strong></div><div><span>合計電流[A]</span><strong>${formatNumber(item.result?.totalCurrent,2)}</strong></div><div><span>電圧降下[%]</span><strong>${formatNumber(item.result?.voltageDropPercent,2)}</strong></div></div><div class="inline-actions top-gap"><button class="ghost small js-open">この案を開く</button>${isHistory?'<button class="ghost small js-save-history">保存済みに追加</button>':`<button class="ghost small js-compare">${selected?'比較から外す':'比較に追加'}</button><button class="ghost small js-delete">削除</button>`}</div>`; div.querySelector('.js-open').onclick=()=>{ state=structuredClone(item.input); state.lastResult=structuredClone(item.result); renderAll(); switchScreen('calc'); }; div.querySelector('.js-save-history')?.addEventListener('click',()=>{ const title=prompt('保存名を入力してください',item.title); if(!title) return; savedItems.unshift({...item,id:uid(),title,savedAt:new Date().toISOString()}); savedItems=savedItems.slice(0,MAX_SAVED_ITEMS); persistState(); renderSaved(); }); div.querySelector('.js-compare')?.addEventListener('click',()=>{ if(selected) compareIds=compareIds.filter(id=>id!==item.id); else if(compareIds.length<3) compareIds.push(item.id); else showToast('比較は最大3件です。'); persistState(); renderSaved(); }); div.querySelector('.js-delete')?.addEventListener('click',()=>{ if(confirm('削除しますか？')){ savedItems=savedItems.filter(i=>i.id!==item.id); compareIds=compareIds.filter(id=>id!==item.id); persistState(); renderSaved(); } }); return div; }
function renderSaved(){ const savedBox=$('saved-subview-saved'), histBox=$('saved-subview-history'), compBox=$('saved-subview-compare'); if(!savedBox) return; savedBox.innerHTML=''; sortItems(savedItems).forEach(item=>savedBox.appendChild(buildSaveCard(item,false))); if(!savedItems.length) savedBox.innerHTML='<div class="panel muted">保存済みデータはありません。</div>'; histBox.innerHTML=''; sortItems(historyItems).forEach(item=>histBox.appendChild(buildSaveCard(item,true))); if(!historyItems.length) histBox.innerHTML='<div class="panel muted">履歴はありません。</div>'; renderCompare(compBox); }
function renderCompare(box){ const items=compareIds.map(id=>savedItems.find(i=>i.id===id)).filter(Boolean); if(!items.length){ box.innerHTML='<div class="panel muted">比較対象を保存済みから追加してください。</div>'; return; } const fields=[['保存名',i=>i.title],['判定',i=>i.result?.judgement],['推奨開閉器[A]',i=>i.result?.adoptedBreaker],['判定対象ケーブル',i=>`${i.result?.cableType||''} ${i.result?.cableSize||''}sq`],['合計電流[A]',i=>formatNumber(i.result?.totalCurrent,2)],['電圧降下[%]',i=>formatNumber(i.result?.voltageDropPercent,2)],['合計概算質量[kg]',i=>formatNumber(i.result?.massTotalKg,1)]]; box.innerHTML=`<div class="compare-card"><div class="compare-table-wrap"><table class="compare-table"><thead><tr><th>項目</th>${items.map(i=>`<th>${escapeHtml(i.title)}</th>`).join('')}</tr></thead><tbody>${fields.map(([label,fn])=>{ const vals=items.map(fn); const diff=new Set(vals.map(String)).size>1; return `<tr class="${diff?'diff':''}"><th>${label}</th>${vals.map(v=>`<td>${escapeHtml(v)}</td>`).join('')}</tr>`; }).join('')}</tbody></table></div></div>`; }
function switchSavedTab(tab){ activeSavedTab=tab; document.querySelectorAll('.saved-seg').forEach(btn=>btn.classList.toggle('active',btn.dataset.savedTab===tab)); document.querySelectorAll('.saved-subview').forEach(el=>el.classList.remove('active')); $(`saved-subview-${tab}`).classList.add('active'); }
function switchScreen(screen){ Object.entries(screens).forEach(([key,el])=>el.classList.toggle('active',key===screen)); document.querySelectorAll('.nav-btn').forEach(btn=>btn.classList.toggle('active',btn.dataset.screen===screen)); if(screen==='docs') renderDocs(); if(screen==='saved') renderSaved(); }
function updateGroundResult(){ const gt=$('groundType').value, wt=$('groundWireType').value, breaker=num(state.lastResult?.adoptedBreaker || state.existingBreaker || 0); if(!gt||!wt){ $('groundResult').textContent='条件を選択すると参考サイズを表示します。'; return; } const rule=GROUND_RULES.find(v=>v.groundType===gt && v.wireType===wt && breaker<=v.maxBreaker) || GROUND_RULES.find(v=>v.groundType===gt && v.wireType===wt); $('groundResult').textContent = rule ? `推奨開閉器 ${breaker || '-'}A の参考接地線サイズ：${rule.size}` : '条件に合う参考サイズがありません。'; }
function clearInputs(){ state=createFreshState(); renderAll(); showToast('入力値をクリアしました。'); }
function runDisclaimer(){ if(localStorage.getItem(STORAGE.disclaimer)==='accepted') return; disclaimerStep=1; $('disclaimerTitle').textContent='免責事項'; $('disclaimerBody').textContent='本Webアプリおよび帳票出力内容は参考資料です。計算結果は現場条件・仕様・関係法令により変わります。'; $('disclaimerDialog').showModal(); $('disclaimerNextBtn').onclick=()=>{ if(disclaimerStep===1){ disclaimerStep=2; $('disclaimerTitle').textContent='重要な確認'; $('disclaimerBody').textContent='最終判断は利用者責任で行ってください。内線規定、関係法令、現場条件、機器仕様、保護協調等を必ず確認してください。'; } else { localStorage.setItem(STORAGE.disclaimer,'accepted'); $('disclaimerDialog').close(); } }; }
function registerSW(){ if('serviceWorker' in navigator) navigator.serviceWorker.register('./sw.js').catch(()=>{}); }
function bindEvents(){ document.querySelectorAll('.nav-btn').forEach(btn=>btn.addEventListener('click',()=>switchScreen(btn.dataset.screen))); document.querySelectorAll('.seg').forEach(btn=>btn.addEventListener('click',()=>{ state.calculationType=btn.dataset.calcType; normalizePowerSystemForCalcType(); persistState(); renderAll(); })); document.querySelectorAll('.saved-seg').forEach(btn=>btn.addEventListener('click',()=>switchSavedTab(btn.dataset.savedTab))); ['calcMode','powerSystem','voltage','powerFactor','efficiency','existingBreaker','breakerMarginRatio','cableSizingMode','installationMethod','layingCondition','ambientTemperature','parallelCount'].forEach(id=>$(id).addEventListener('change',()=>{ state[id]=$(id).value; persistState(); renderAll(); validateRealtime(); })); $('loadCount').addEventListener('change',()=>{ state.loadCount=$('loadCount').value; normalizeLoads(); persistState(); renderAll(); }); $('cableType').addEventListener('change',()=>{ state.cableType=$('cableType').value; state.cableSize=''; state.baseAmpacity=''; state.ampacityMode='none'; persistState(); renderAll(); }); $('cableSize').addEventListener('change',()=>{ state.cableSize=$('cableSize').value; const info=cableInfo(state.cableType,state.cableSize); state.baseAmpacity=info?.ampacity?String(info.ampacity):''; state.ampacityMode=info?.ampacity?'auto':'none'; persistState(); renderAll(); }); $('baseAmpacity').addEventListener('input',()=>{ state.baseAmpacity=$('baseAmpacity').value; state.ampacityMode=state.baseAmpacity?'manual':'none'; persistState(); renderAmpacitySection(); }); ['projectName','constructionType','submittedTo','drawingNo','createdBy','projectRemarks','wiringLength'].forEach(id=>$(id).addEventListener('input',()=>{ state[id]=$(id).value; persistState(); renderAmpacitySection(); })); $('calculateBtn').addEventListener('click',calculate); $('toggleResultBtn').addEventListener('click',()=>{ $('resultBody').classList.toggle('hidden'); $('toggleResultBtn').textContent=$('resultBody').classList.contains('hidden')?'展開する':'折りたたむ'; }); $('saveResultTopBtn').addEventListener('click',openSaveDialog); $('saveResultBottomBtn').addEventListener('click',openSaveDialog); $('confirmSaveBtn').addEventListener('click',e=>{ e.preventDefault(); confirmSave(); }); $('csvBtn').addEventListener('click',downloadCsv); $('excelBtn').addEventListener('click',downloadExcel); $('pdfBtn').addEventListener('click',printPdf); $('groundWireBtn').addEventListener('click',()=>$('groundDialog').showModal()); $('closeGroundDialog').addEventListener('click',()=>$('groundDialog').close()); $('groundType').addEventListener('change',updateGroundResult); $('groundWireType').addEventListener('change',updateGroundResult); $('docsSearch').addEventListener('input',renderDocs); $('docsSearchClear').addEventListener('click',()=>{ $('docsSearch').value=''; renderDocs(); }); $('savedSort').addEventListener('change',()=>{ persistState(); renderSaved(); }); $('displayScale').addEventListener('change',()=>{ state.displayScale=$('displayScale').value; persistState(); applyDisplayScale(); }); $('clearInputsBtn').addEventListener('click',clearInputs); $('resetDisclaimerBtn').addEventListener('click',()=>{ localStorage.removeItem(STORAGE.disclaimer); showToast('次回起動時に免責を表示します。'); }); $('openDocsFromCalc').addEventListener('click',()=>switchScreen('docs')); window.addEventListener('beforeinstallprompt',e=>{ e.preventDefault(); deferredPrompt=e; $('installBtn').hidden=false; }); $('installBtn').addEventListener('click',async()=>{ if(!deferredPrompt) return; deferredPrompt.prompt(); deferredPrompt=null; $('installBtn').hidden=true; }); }
function init(){ bindEvents(); renderAll(); switchSavedTab(activeSavedTab); runDisclaimer(); registerSW(); }
document.addEventListener('DOMContentLoaded', init);
